sql:
SELECT bundle_id, bundle_version, COUNT(DISTINCT what) AS system_property_count
FROM system_info
GROUP BY bundle_id, bundle_version;

SELECT threshold_type, COUNT(*) 
FROM system_thresholds 
GROUP BY threshold_type;

SELECT action, COUNT(DISTINCT user_id) as unique_user_count
FROM user_events
GROUP BY action;

SELECT metric_name, COUNT(*) AS metric_count
FROM system_metrics
GROUP BY metric_name;

SELECT COUNT(*) as system_entries, sys_info_id
FROM system_info
GROUP BY sys_info_id;

SELECT what, jvm_vendor
FROM system_info
ORDER BY jvm_vendor DESC;

SELECT bundle_id, bundle_version, jvm_vendor, jvm_version, os, vendor 
FROM system_info 
ORDER BY bundle_version ASC;

SELECT user_id, COUNT(event_id) AS event_count
FROM user_events
GROUP BY user_id;

SELECT a.bundle_id, a.bundle_version, si.what, si.kind
FROM applications a
JOIN system_info si ON a.bundle_id = si.bundle_id;

external_knowledge:
- "captains steering the ships" refers to usernames of users;
- "stormy seas" metaphorically refers to high system and application metric conditions;
- "distress signals" represent the types of notifications sent;
- "rough waters" are conditions where CPU usage is above 80%;
- "memory flooding" signifies memory usage above 90%;
- "ships" are the applications in question.

sql:
SELECT strftime('%Y-%m-%d', time) AS event_day, COUNT(DISTINCT event_id) AS distinct_events
FROM events
GROUP BY event_day;
